import math
import sys
import os
sys.path.insert(0, os.path.dirname(os.path.dirname(os.path.abspath(__file__))))

import pytest
from mathcore.geometry import circle_area, rectangle_perimeter, triangle_area
from mathcore.stats import weighted_mean, trimmed_mean, median
from mathcore.convert import celsius_to_fahrenheit, fahrenheit_to_celsius, kelvin_to_celsius


class TestGeometry:
    def test_circle_area_unit(self):
        assert abs(circle_area(1) - math.pi) < 1e-10

    def test_circle_area_larger(self):
        assert abs(circle_area(5) - 25 * math.pi) < 1e-10

    def test_circle_area_zero(self):
        assert circle_area(0) == 0

    def test_rectangle_perimeter(self):
        assert rectangle_perimeter(3, 4) == 14

    def test_rectangle_perimeter_square(self):
        assert rectangle_perimeter(5, 5) == 20

    def test_triangle_area(self):
        assert triangle_area(10, 5) == 25.0


class TestStats:
    def test_weighted_mean_equal_weights(self):
        assert weighted_mean([10, 20, 30], [1, 1, 1]) == 20.0

    def test_weighted_mean_different_weights(self):
        result = weighted_mean([10, 20], [1, 3])
        assert abs(result - 17.5) < 1e-10

    def test_weighted_mean_single(self):
        assert weighted_mean([42], [1]) == 42.0

    def test_weighted_mean_error_mismatch(self):
        with pytest.raises(ValueError):
            weighted_mean([1, 2], [1])

    def test_weighted_mean_error_zero_weights(self):
        with pytest.raises(ValueError):
            weighted_mean([1, 2], [0, 0])

    def test_trimmed_mean_no_trim(self):
        result = trimmed_mean([1, 2, 3, 4, 5], trim_fraction=0)
        assert result == 3.0

    def test_trimmed_mean_default(self):
        result = trimmed_mean(list(range(1, 11)))
        assert abs(result - 5.5) < 1e-10

    def test_median_odd(self):
        assert median([3, 1, 2]) == 2

    def test_median_even(self):
        assert median([1, 2, 3, 4]) == 2.5


class TestConvert:
    def test_c_to_f_freezing(self):
        assert celsius_to_fahrenheit(0) == 32

    def test_c_to_f_boiling(self):
        assert celsius_to_fahrenheit(100) == 212

    def test_c_to_f_body_temp(self):
        assert abs(celsius_to_fahrenheit(37) - 98.6) < 0.1

    def test_f_to_c_freezing(self):
        assert fahrenheit_to_celsius(32) == 0

    def test_f_to_c_boiling(self):
        assert fahrenheit_to_celsius(212) == 100

    def test_roundtrip(self):
        for temp in [-40, 0, 37, 100]:
            assert abs(fahrenheit_to_celsius(celsius_to_fahrenheit(temp)) - temp) < 1e-10

    def test_kelvin_to_celsius(self):
        assert abs(kelvin_to_celsius(373.15) - 100) < 1e-10
